const gmailData = $items("Aggregate"); 
const githubData = $items("Aggregate1");

const now = new Date();
const oneHourAgo = new Date(now.getTime() - (60 * 60 * 1000));
const trTime = new Date(now.getTime() + (3 * 60 * 60 * 1000));
const currentHour = trTime.getUTCHours();

let recentGithubEvents = 0;
githubData.forEach(item => {
    if (item.json && item.json.created_at) {
        const eventTime = new Date(item.json.created_at);
        if (eventTime >= oneHourAgo) {
            recentGithubEvents++;
        }
    }
});

const recentGmailCount = gmailData.length;
let anomalyScore = 0;
let findings = [];

if (currentHour >= 0 && currentHour <= 6) {
    if (recentGithubEvents > 0) {
        anomalyScore += 70;
        findings.push(`KRİTİK: Gece ${currentHour}:00'de ${recentGithubEvents} GitHub işlemi!`);
    }
    if (recentGmailCount > 10) {
        anomalyScore += 30;
        findings.push(`ŞÜPHELİ: Gece yoğun mail trafiği (${recentGmailCount} adet).`);
    }
}

if (recentGmailCount > 50) {
    anomalyScore += 40;
    findings.push("UYARI: Beklenmedik mail hacmi patlaması.");
}

let status = "GÜVENLİ";
if (anomalyScore >= 80) status = "TEHLİKE";
else if (anomalyScore >= 40) status = "DİKKAT";

// Hata verdirmesi imkansız saat formatı
const timeString = trTime.toISOString().substring(11, 19);

return {
    sentinel_report: {
      status: status,
      risk_puani: `%${anomalyScore}`,
      analiz_zamani: timeString,
      veriler: {
        son_1_saat_mail: recentGmailCount,
        son_1_saat_github: recentGithubEvents
      },
      tespitler: findings.length > 0 ? findings : ["Sistem stabil, anomali saptanmadı."]
    }
};

